import axios from 'axios';
const api = axios.create({ baseURL: 'http://localhost:8000/api', withCredentials: true });
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('admin_access_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});
let isRefreshing = false, failedQueue = [];
const processQueue = (error, token = null) => { failedQueue.forEach(p => error ? p.reject(error) : p.resolve(token)); failedQueue = []; };
api.interceptors.response.use(r => r, async (error) => {
  const original = error.config;
  if (error.response?.status === 401 && !original._retry) {
    if (isRefreshing) return new Promise((res, rej) => failedQueue.push({ resolve: res, reject: rej })).then(t => { original.headers.Authorization = `Bearer ${t}`; return api(original); });
    original._retry = true; isRefreshing = true;
    try {
      const { data } = await axios.post('http://localhost:8000/api/auth/token/refresh/', {}, { withCredentials: true });
      localStorage.setItem('admin_access_token', data.access);
      processQueue(null, data.access);
      original.headers.Authorization = `Bearer ${data.access}`;
      return api(original);
    } catch (err) {
      processQueue(err, null);
      localStorage.removeItem('admin_access_token');
      localStorage.removeItem('admin_user');
      window.location.href = '/login';
      return Promise.reject(err);
    } finally { isRefreshing = false; }
  }
  return Promise.reject(error);
});
export default api;
